3	import (
4		"fmt"
5		"time"
6	)
7	
8	const queueRankKey = "queue-rank"
9	const queueRankStep = 10
10	
11	type queueOp int
12	
13	const (
14		queueOpTop queueOp = iota
15		queueOpMoveBefore
16		queueOpMoveAfter
17	)
18	
19	// QueueTop moves a bead to the front of its priority bucket.
20	func (s *Store) QueueTop(id string) error {
21		return s.queueReorder(id, "", queueOpTop)
22	}
23	
24	// QueueMove reorders a bead relative to another bead in the same priority bucket.
25	func (s *Store) QueueMove(id, otherID string, before bool) error {
26		if before {
27			return s.queueReorder(id, otherID, queueOpMoveBefore)
28		}
29		return s.queueReorder(id, otherID, queueOpMoveAfter)
30	}
31	
32	// QueueClear removes the explicit queue-rank from a bead.
33	func (s *Store) QueueClear(id string) error {
34		return s.WithLock(func() error {
35			beads, _, err := s.readAllLatestRaw()
36			if err != nil {
37				return err
38			}
39	
40			now := time.Now().UTC()
41			found := false
42			for i := range beads {
43				if beads[i].ID != id {
44					continue
45				}
46				found = true
47				if beads[i].Extra != nil {
48					delete(beads[i].Extra, queueRankKey)
49					if len(beads[i].Extra) == 0 {
50						beads[i].Extra = nil
51					}
52				}
53				beads[i].UpdatedAt = now
54				break
55			}
56			if !found {
57				return fmt.Errorf("bead: not found: %s", id)
58			}
59			return s.WriteAll(beads)
60		})
61	}
62	
63	func (s *Store) queueReorder(id, otherID string, op queueOp) error {
64		return s.WithLock(func() error {
65			beads, _, err := s.readAllLatestRaw()
66			if err != nil {
67				return err
68			}
69	
70			indexByID := make(map[string]int, len(beads))
71			for i := range beads {
72				indexByID[beads[i].ID] = i
73			}
74	
75			targetIdx, ok := indexByID[id]
76			if !ok {
77				return fmt.Errorf("bead: not found: %s", id)
78			}
79	
80			targetPriority := beads[targetIdx].Priority
81			if op != queueOpTop {
82				otherIdx, ok := indexByID[otherID]
83				if !ok {
84					return fmt.Errorf("bead: not found: %s", otherID)
85				}
86				if beads[otherIdx].Priority != targetPriority {
87					return fmt.Errorf("bead: queue move limited to one priority bucket: %s (P%d) and %s (P%d)", id, targetPriority, otherID, beads[otherIdx].Priority)
88				}
89			}
90	
91			bucket := make([]Bead, 0, len(beads))
92			for _, bead := range beads {
93				if bead.Priority == targetPriority {
94					bucket = append(bucket, bead)
95				}
96			}
97			if len(bucket) == 0 {
98				return fmt.Errorf("bead: not found: %s", id)
99			}
100	
101			sortBeadsForQueue(bucket)
102			desired := reorderQueueBucket(bucket, id, otherID, op)
103	
104			if rank, ok := queueTargetRank(desired, id); ok {
105				now := time.Now().UTC()
106				idx := indexByID[id]
107				if beads[idx].Extra == nil {
108					beads[idx].Extra = make(map[string]any)
109				}
110				beads[idx].Extra[queueRankKey] = rank
111				beads[idx].UpdatedAt = now
112				return s.WriteAll(beads)
113			}
114	
115			now := time.Now().UTC()
116			for i, bead := range desired {
117				idx := indexByID[bead.ID]
118				if beads[idx].Extra == nil {
119					beads[idx].Extra = make(map[string]any)
120				}
121				beads[idx].Extra[queueRankKey] = i * queueRankStep
122				beads[idx].UpdatedAt = now
123			}
124	
125			return s.WriteAll(beads)
126		})
127	}
128	
129	func queueTargetRank(desired []Bead, targetID string) (int, bool) {
130		targetIdx := -1
131		for i, bead := range desired {
132			if bead.ID == targetID {
133				targetIdx = i
134				break
135			}
136		}
137		if targetIdx < 0 {
138			return 0, false
139		}
140	
141		for i := 0; i < targetIdx; i++ {
142			if _, ok := parseQueueRank(desired[i].Extra[queueRankKey]); !ok {
143				return 0, false
144			}
145		}
146	
147		var prevRank *int
148		for i := targetIdx - 1; i >= 0; i-- {
149			if rank, ok := parseQueueRank(desired[i].Extra[queueRankKey]); ok {
150				prevRank = &rank
151				break
152			}
153		}
154	
155		var nextRank *int
156		for i := targetIdx + 1; i < len(desired); i++ {
157			if rank, ok := parseQueueRank(desired[i].Extra[queueRankKey]); ok {
158				nextRank = &rank
159				break
160			}
161		}
162	
163		switch {
164		case prevRank != nil && nextRank != nil:
165			if *nextRank-*prevRank <= 1 {
166				return 0, false
167			}
168			return (*prevRank + *nextRank) / 2, true
169		case prevRank != nil:
170			return *prevRank + 1, true
171		case nextRank != nil:
172			return *nextRank - 1, true
173		default:
174			return 0, true
175		}
176	}
177	
178	func reorderQueueBucket(bucket []Bead, targetID, otherID string, op queueOp) []Bead {
179		if len(bucket) <= 1 {
180			return bucket
181		}
182	
183		targetIdx := -1
184		otherIdx := -1
185		for i, bead := range bucket {
186			switch bead.ID {
187			case targetID:
188				targetIdx = i
189			case otherID:
190				otherIdx = i
191			}
192		}
193		if targetIdx < 0 {
194			return bucket
195		}
196	
197		out := append([]Bead(nil), bucket...)
198		target := out[targetIdx]
199		out = append(out[:targetIdx], out[targetIdx+1:]...)
200	
201		switch op {
202		case queueOpTop:
203			return append([]Bead{target}, out...)
204		case queueOpMoveBefore, queueOpMoveAfter:
205			if otherIdx < 0 || targetID == otherID {
206				return bucket
207			}
208			if targetIdx < otherIdx {
209				otherIdx--
210			}
211			insertAt := otherIdx
212			if op == queueOpMoveAfter {
213				insertAt++
214			}
215			if insertAt < 0 {
216				insertAt = 0
217			}
218			if insertAt > len(out) {
219				insertAt = len(out)
220			}
221			out = append(out, Bead{})
222			copy(out[insertAt+1:], out[insertAt:])
223			out[insertAt] = target
224			return out
225		default:
226			return bucket
227		}
228	}
