156	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount int, now time.Time) (ReconcilePlan, bool) {
157		p := ReconcilePlan{
158			BeadID:        b.ID,
159			CurrentFields: currentLifecycleFields(b),
160		}
161		latest := latestLifecycleEvent(events)
162	
163		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
164			p.Reason = "closed bead has stale no_changes lifecycle metadata"
165			p.ClearFields = noChangesFieldsPresent(b)
166			p.RemoveLabels = noChangesLabelsPresent(b)
167			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
168		}
169	
170		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
171			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
172			p.ClearFields = noChangesFieldsPresent(b)
173			p.RemoveLabels = noChangesLabelsPresent(b)
174			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
175		}
176	
177		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
178			p.Reason = "verified no_changes evidence closes as already_satisfied"
179			p.ClearFields = noChangesFieldsPresent(b)
180			p.RemoveLabels = noChangesLabelsPresent(b)
181			p.CloseSatisfied = true
182			return p, true
183		}
184	
185		if isNoViableProviderEvent(latest) && hasLabel(b, LabelNeedsInvestigation) {
186			p.Reason = "no_viable_provider is retryable transport state; clear stale needs-investigation label"
187			p.RemoveLabels = []string{LabelNeedsInvestigation}
188			return p, true
189		}
190	
191		if hasLabel(b, LabelNeedsInvestigation) || latest.Kind == "no_changes_needs_investigation" {
192			if hasRetryAfter(b) || hasAnyExtra(b, ExtraLastStatus, ExtraLastDetail) {
193				p.Reason = "needs_investigation is non-retryable; clear cooldown metadata"
194				p.ClearFields = noChangesFieldsPresent(b)
195				if !hasLabel(b, LabelNeedsInvestigation) {
196					p.AddLabels = append(p.AddLabels, LabelNeedsInvestigation)
197				}
198				return p, len(p.ClearFields) > 0 || len(p.AddLabels) > 0
199			}
200		}
201	
202		if isExpiredRetryAfter(b, now) {
203			p.Reason = "expired retry-after metadata no longer blocks execution"
204			p.ClearFields = []string{ExtraRetryAfter}
205			return p, true
206		}
207	
208		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
209			if b.Extra != nil {
210				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
211					return ReconcilePlan{}, false
212				}
213			}
214			p.Reason = "parent/epic work is owned by child beads"
215			p.SetFields = map[string]any{
216				ExtraExecutionElig:   false,
217				ExtraExecutionReason: "parent/epic container; execute child beads first",
218			}
219			return p, true
220		}
221	
222		return ReconcilePlan{}, false
223	}
