1805	func (s *Store) Status() (*StatusCounts, error) {
1806		beads, err := s.ReadAll()
1807		if err != nil {
1808			return nil, err
1809		}
1810		ready, err := s.Ready()
1811		if err != nil {
1812			return nil, err
1813		}
1814		blocked, err := s.Blocked()
1815		if err != nil {
1816			return nil, err
1817		}
1818		workerReady, err := s.ReadyExecution()
1819		if err != nil {
1820			return nil, err
1821		}
1822		needsHuman, err := s.NeedsHuman()
1823		if err != nil {
1824			return nil, err
1825		}
1826	
1827		// Pull in archive partner so totals survive `bead migrate` — the archive
1828		// only carries closed beads, so Ready/Blocked aren't affected.
1829		seen := make(map[string]bool, len(beads))
1830		all := make([]Bead, 0, len(beads))
1831		for _, b := range beads {
1832			if seen[b.ID] {
1833				continue
1834			}
1835			seen[b.ID] = true
1836			all = append(all, b)
1837		}
1838		if s.Collection == DefaultCollection {
1839			archive := s.archivePartner()
1840			if archived, aerr := archive.ReadAll(); aerr == nil {
1841				for _, b := range archived {
1842					if seen[b.ID] {
1843						continue
1844					}
1845					seen[b.ID] = true
1846					all = append(all, b)
1847				}
1848			}
1849		}
1850	
1851		counts := &StatusCounts{
1852			Total:       len(all),
1853			Ready:       len(ready),
1854			Blocked:     len(blocked),
1855			WorkerReady: len(workerReady),
1856			NeedsHuman:  len(needsHuman),
1857		}
1858		for _, b := range all {
1859			switch b.Status {
1860			case StatusOpen:
1861				counts.Open++
1862			case StatusClosed:
1863				counts.Closed++
1864			}
1865		}
1866		return counts, nil
1867	}
