18	// runScriptFn executes a directive file against opts.WorkDir using real filesystem
19	// and git operations. The directive file path is taken from opts.Model (if it is
20	// a readable file) or from opts.PromptFile as a fallback.
21	func runScriptFn(r *Runner, opts RunArgs) (*Result, error) {
22		start := time.Now()
23	
24		// Resolve directive file: opts.Model first, then opts.PromptFile.
25		directivePath := opts.Model
26		if directivePath == "" || !isReadableFile(directivePath) {
27			if opts.PromptFile != "" {
28				directivePath = opts.PromptFile
29			}
30		}
31		if directivePath == "" {
32			return nil, fmt.Errorf("script harness: no directive file (set --model or --prompt-file)")
33		}
34	
35		data, err := os.ReadFile(directivePath)
36		if err != nil {
37			return nil, fmt.Errorf("script harness: read directive file %s: %w", directivePath, err)
38		}
39	
40		workDir := opts.WorkDir
41		if workDir == "" {
42			workDir = "."
43		}
44	
45		var outputLines []string
46		exitCode := 0
47		var execErr error
48	
49		directives := parseDirectives(string(data))
50	
51		// Build env interpolation map from Correlation.
52		envMap := map[string]string{
53			"DDX_BEAD_ID":         "",
54			"DDX_ATTEMPT_ID":      "",
55			"DDX_WORKER_ID":       "",
56			"DDX_SESSION_LOG_DIR": opts.SessionLogDir,
57		}
58		if opts.Correlation != nil {
59			if v, ok := opts.Correlation["bead_id"]; ok {
60				envMap["DDX_BEAD_ID"] = v
61			}
62			if v, ok := opts.Correlation["attempt_id"]; ok {
63				envMap["DDX_ATTEMPT_ID"] = v
64			}
65			if v, ok := opts.Correlation["worker_id"]; ok {
66				envMap["DDX_WORKER_ID"] = v
67			}
68		}
69		expand := func(s string) string {
70			return os.Expand(s, func(key string) string {
71				return envMap[key]
72			})
73		}
74	
75		for i, d := range directives {
76			verb := d[0]
77			args := d[1:]
78	
79			switch verb {
80			case "no-op":
81				outputLines = append(outputLines, "no-op")
82	
83			case "set-exit":
84				if len(args) < 1 {
85					execErr = fmt.Errorf("script harness: set-exit requires an argument")
86					goto done
87				}
88				n, err := strconv.Atoi(args[0])
89				if err != nil {
90					execErr = fmt.Errorf("script harness: set-exit: invalid code %q", args[0])
91					goto done
92				}
93				exitCode = n
94	
95			case "sleep-ms":
96				if len(args) < 1 {
97					execErr = fmt.Errorf("script harness: sleep-ms requires an argument")
98					goto done
99				}
100				n, err := strconv.Atoi(args[0])
101				if err != nil {
102					execErr = fmt.Errorf("script harness: sleep-ms: invalid duration %q", args[0])
103					goto done
104				}
105				time.Sleep(time.Duration(n) * time.Millisecond)
106	
107			case "fail-during":
108				if len(args) < 1 {
109					execErr = fmt.Errorf("script harness: fail-during requires an argument")
110					goto done
111				}
112				n, err := strconv.Atoi(args[0])
113				if err != nil {
114					execErr = fmt.Errorf("script harness: fail-during: invalid index %q", args[0])
115					goto done
116				}
117				if i == n {
118					execErr = fmt.Errorf("script harness: synthetic failure at directive %d", i)
119					goto done
120				}
121	
122			case "append-line":
123				if len(args) < 2 {
124					execErr = fmt.Errorf("script harness: append-line requires path and text")
125					goto done
126				}
127				path, err := resolvePath(workDir, expand(args[0]))
128				if err != nil {
129					execErr = err
130					goto done
131				}
132				text := expand(strings.Join(args[1:], " "))
133				if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
134					execErr = fmt.Errorf("script harness: append-line mkdir: %w", err)
135					goto done
136				}
137				f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
138				if err != nil {
139					execErr = fmt.Errorf("script harness: append-line open: %w", err)
140					goto done
141				}
142				_, werr := fmt.Fprintln(f, text)
143				f.Close()
144				if werr != nil {
145					execErr = fmt.Errorf("script harness: append-line write: %w", werr)
146					goto done
147				}
148				outputLines = append(outputLines, fmt.Sprintf("append-line %s", args[0]))
149	
150			case "create-file":
151				if len(args) < 2 {
152					execErr = fmt.Errorf("script harness: create-file requires path and content")
153					goto done
154				}
155				path, err := resolvePath(workDir, expand(args[0]))
156				if err != nil {
157					execErr = err
158					goto done
159				}
160				content := expand(strings.Join(args[1:], " "))
161				if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
162					execErr = fmt.Errorf("script harness: create-file mkdir: %w", err)
163					goto done
164				}
165				if err := os.WriteFile(path, []byte(content), 0644); err != nil {
166					execErr = fmt.Errorf("script harness: create-file write: %w", err)
167					goto done
168				}
169				outputLines = append(outputLines, fmt.Sprintf("create-file %s", args[0]))
170	
171			case "delete-file":
172				if len(args) < 1 {
173					execErr = fmt.Errorf("script harness: delete-file requires a path")
174					goto done
175				}
176				path, err := resolvePath(workDir, expand(args[0]))
177				if err != nil {
178					execErr = err
179					goto done
180				}
181				if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
182					execErr = fmt.Errorf("script harness: delete-file: %w", err)
183					goto done
184				}
185				outputLines = append(outputLines, fmt.Sprintf("delete-file %s", args[0]))
186	
187			case "modify-line":
188				if len(args) < 3 {
189					execErr = fmt.Errorf("script harness: modify-line requires path, regex, and replacement")
190					goto done
191				}
192				path, err := resolvePath(workDir, expand(args[0]))
193				if err != nil {
194					execErr = err
195					goto done
196				}
197				pattern := expand(args[1])
198				repl := expand(strings.Join(args[2:], " "))
199				re, err := regexp.Compile(pattern)
200				if err != nil {
201					execErr = fmt.Errorf("script harness: modify-line: bad regex %q: %w", pattern, err)
202					goto done
203				}
204				raw, err := os.ReadFile(path)
205				if err != nil {
206					execErr = fmt.Errorf("script harness: modify-line read: %w", err)
207					goto done
208				}
209				lines := strings.Split(string(raw), "\n")
210				for li, line := range lines {
211					if re.MatchString(line) {
212						lines[li] = re.ReplaceAllString(line, repl)
213						break
214					}
215				}
216				if err := os.WriteFile(path, []byte(strings.Join(lines, "\n")), 0644); err != nil {
217					execErr = fmt.Errorf("script harness: modify-line write: %w", err)
218					goto done
219				}
220				outputLines = append(outputLines, fmt.Sprintf("modify-line %s", args[0]))
221	
222			case "run":
223				if len(args) < 1 {
224					execErr = fmt.Errorf("script harness: run requires a shell command")
225					goto done
226				}
227				shell := expand(strings.Join(args, " "))
228				cmd := exec.Command("sh", "-c", shell)
229				cmd.Dir = workDir
230				cmd.Env = scrubbedGitEnvScript()
231				out, err := cmd.CombinedOutput()
232				outputLines = append(outputLines, strings.TrimRight(string(out), "\n"))
233				if err != nil {
234					execErr = fmt.Errorf("script harness: run %q: %w", shell, err)
235					goto done
236				}
237	
238			case "commit":
239				if len(args) < 1 {
240					execErr = fmt.Errorf("script harness: commit requires a message")
241					goto done
242				}
243				msg := expand(strings.Join(args, " "))
244				if err := gitCommitAll(workDir, msg); err != nil {
245					execErr = fmt.Errorf("script harness: commit: %w", err)
246					goto done
247				}
248				outputLines = append(outputLines, fmt.Sprintf("commit %q", msg))
249	
250			default:
251				execErr = fmt.Errorf("script harness: unknown directive %q at index %d", verb, i)
252				goto done
253			}
254		}
255	
256	done:
257		elapsed := time.Since(start)
258		sessionID := fmt.Sprintf("script-%d", start.UnixNano())
259	
260		result := &Result{
261			Harness:        "script",
262			Provider:       "script",
263			RouteReason:    "direct-override",
264			Model:          directivePath,
265			Output:         strings.Join(outputLines, "\n"),
266			ExitCode:       exitCode,
267			DurationMS:     int(elapsed.Milliseconds()),
268			AgentSessionID: sessionID,
269		}
270		if execErr != nil {
271			result.Error = execErr.Error()
272			if result.ExitCode == 0 {
273				result.ExitCode = 1
274			}
275		}
276		return result, execErr
277	}
