279	// parseDirectives parses a directive file into a slice of token slices.
280	// Lines starting with # are comments. Empty lines are skipped.
281	// Tokens are whitespace-separated; a quoted string in position 2+ is kept together.
282	func parseDirectives(content string) [][]string {
283		var out [][]string
284		scanner := bufio.NewScanner(strings.NewReader(content))
285		for scanner.Scan() {
286			line := strings.TrimSpace(scanner.Text())
287			if line == "" || strings.HasPrefix(line, "#") {
288				continue
289			}
290			tokens := splitDirective(line)
291			if len(tokens) == 0 {
292				continue
293			}
294			out = append(out, tokens)
295		}
296		return out
297	}
298	
299	// splitDirective splits a directive line into tokens.
300	// Returns [verb, arg1, arg2, ...] where the final argument absorbs any
301	// remaining whitespace-separated words as a single string. Surrounding
302	// double-quotes on the final argument are stripped.
303	//
304	// For directives that need 3 distinct args (modify-line: path regex repl)
305	// we return verb + 3 separate fields: parts[0..2], with parts[3:] joined
306	// onto the last field.
307	//
308	// The heuristic: each case in RunScript knows how many discrete args it
309	// needs and accesses them by index; the split just returns all fields, and
310	// the caller joins args[N:] for the "rest" argument.
311	func splitDirective(line string) []string {
312		// We need to preserve the raw fields so callers can pick the right number.
313		// Return all whitespace-split tokens; the final quoted token has quotes stripped.
314		parts := strings.Fields(line)
315		if len(parts) == 0 {
316			return nil
317		}
318		// Strip quotes from the last token if the entire last token is quoted.
319		last := parts[len(parts)-1]
320		if len(last) >= 2 && last[0] == '"' && last[len(last)-1] == '"' {
321			parts[len(parts)-1] = last[1 : len(last)-1]
322		}
323		return parts
324	}
325	
326	// resolvePath resolves a relative path against workDir and rejects absolute paths.
327	func resolvePath(workDir, path string) (string, error) {
328		if filepath.IsAbs(path) {
329			return "", fmt.Errorf("script harness: absolute path rejected: %s", path)
330		}
331		return filepath.Join(workDir, path), nil
332	}
333	
334	// gitCommitAll runs git add -A && git commit -m msg in dir with scrubbed GIT_* env.
335	func gitCommitAll(dir, msg string) error {
336		for _, args := range [][]string{
337			{"add", "-A"},
338			{"commit", "-m", msg},
339		} {
340			cmd := internalgit.Command(context.Background(), dir, args...)
341			if out, err := cmd.CombinedOutput(); err != nil {
342				return fmt.Errorf("git %v: %w\n%s", args, err, out)
343			}
344		}
345		return nil
346	}
347	
348	// scrubbedGitEnvScript returns the environment with all GIT_* variables removed.
349	func scrubbedGitEnvScript() []string {
350		parent := os.Environ()
351		env := make([]string, 0, len(parent))
352		for _, kv := range parent {
353			if strings.HasPrefix(kv, "GIT_") {
354				continue
355			}
356			env = append(env, kv)
357		}
358		return env
359	}
360	
361	// isReadableFile returns true if path points to a regular, readable file.
362	func isReadableFile(path string) bool {
363		fi, err := os.Stat(path)
364		return err == nil && !fi.IsDir()
365	}
